module.render:
const type = (args.type || 'info').toLowerCase();
const map = {
  info: { color: 'var(--info-color, #3b82f6)', glyph: 'ℹ️' },
  success: { color: 'var(--success-color, #22c55e)', glyph: '✅' },
  warning: { color: 'var(--warning-color, #f59e0b)', glyph: '⚠️' },
  danger: { color: 'var(--danger-color, #ef4444)', glyph: '⛔' }
};
const conf = map[type] || map.info;
const msgStr = sections[0] ? sections[0].trim() : '';
return `\n\n<div class="mdp-mod-alert" style="border-left-color: ${conf.color};"><span class="alert-glyph">${conf.glyph}</span><div class="alert-body">\n\n${msgStr}\n\n</div></div>\n\n`;
